  var st=document.createElement('style'); st.id='ntia-style'; st.textContent=css; document.head.appendChild(st);

  var sec=document.createElement('section'); sec.className='ntia'; sec.id='nano-tech';
  sec.innerHTML = ''
   + '<div class="wrap"><div class="ntia-grid">'
   +   '<div>'
   +     '<span class="eyebrow">Nano Technology in Action</span>'
   +     '<h2>What protection looks like.</h2>'
   +     '<p class="ntia-sub">Every roof begins with a Roof Health Score™. We evaluate age, granule condition, flexibility, moisture exposure, and other indicators before making a recommendation.</p>'
