   +     '<p class="ntia-note">Illustrative example only. <span class="flag">[CLAIM REQUIRES DOCUMENTATION]</span> Official Roof Health Scores require an on-site inspection.</p>'
   +   '</div>'
   +   '<div class="rhs-stage" role="img" aria-label="Illustrative roof inspection scan of an asphalt shingle roof, producing an example Roof Health Score of 78 out of 100, likely preservation candidate. Official scores require an on-site inspection.">'
   +     '<div class="rhs-roof"></div><div class="rhs-grain"></div><div class="rhs-vig"></div>'
   +     '<div class="rhs-scan"><div class="rhs-read"><span class="rd-l">Granule Density</span><span class="rd-v">81</span></div></div>'
   +     '<div class="rhs-card" aria-hidden="true"><div class="rc-h">Roof Health Score™</div><div class="rc-score"><span class="rc-num">0</span><span class="rc-den">/ 100</span></div><div class="rc-status">Likely Preservation Candidate</div><div class="rc-disc">Illustrative example only. Inspection required.</div></div>'
   +   '</div>'
   + '</div></div>';
