      num=sec.querySelector('.rc-num'), read=sec.querySelector('.rhs-read'),
      rdl=read.querySelector('.rd-l'), rdv=read.querySelector('.rd-v');
  /* photo-first: use a real photo if it loads, else keep procedural */
  (function(){ var im=new Image(); im.onload=function(){ roof.style.setProperty('--photo',"url('"+ROOF_IMAGE+"')"); roof.classList.add('has-photo'); }; im.src=ROOF_IMAGE; })();

  if(matchMedia('(prefers-reduced-motion: reduce)').matches){ stage.classList.add('scan-static','scan-done'); num.textContent='78'; return; }
  var token=0;
  var reads=[['Granule Density','81'],['UV Exposure','76'],['Flexibility','84'],['Moisture Risk','Low']];
  function count(my){ var s=null; requestAnimationFrame(function r(t){ if(my!==token)return; if(s===null)s=t; var p=Math.min((t-s)/900,1); num.textContent=Math.round(p*78); if(p<1)requestAnimationFrame(r); }); }
  function run(){ token++; var my=token; stage.classList.remove('scan-done','scan-run'); read.classList.remove('show'); void stage.offsetWidth; stage.classList.add('scan-run');
    reads.forEach(function(rr,i){ setTimeout(function(){ if(my!==token)return; read.classList.remove('show');
      setTimeout(function(){ if(my!==token)return; rdl.textContent=rr[0]; rdv.textContent=rr[1]; read.classList.add('show'); },150); }, 600+i*1080); });
    setTimeout(function(){ if(my!==token)return; read.classList.remove('show'); stage.classList.add('scan-done'); count(my); }, 5000);
  }
