(function(){
  var sec=document.getElementById('preserve-first'); if(!sec) return;
  if(matchMedia('(prefers-reduced-motion: reduce)').matches) return; /* static, preserved state */
  var io=new IntersectionObserver(function(es){ es.forEach(function(e){ if(e.isIntersecting){ sec.classList.add('in'); io.disconnect(); } }); }, {threshold:.3});
  io.observe(sec);
})();

