(function(){
  var stage=document.getElementById('pdStage'), grip=document.getElementById('pdGrip');
  if(!stage||!grip) return;
  var AGED_IMAGE="/assets/roof-aged.jpg", PRESERVED_IMAGE="/assets/roof-preserved.jpg";
  [[AGED_IMAGE,'.pd-aged .pd-tex'],[PRESERVED_IMAGE,'.pd-pres .pd-tex']].forEach(function(pr){
    var im=new Image(); im.onload=function(){ var el=stage.querySelector(pr[1]); if(el){ el.style.backgroundImage="url('"+pr[0]+"')"; el.style.filter="none"; } }; im.src=pr[0];
  });
  var p=50, touched=false;
  function set(v){ p=Math.max(0,Math.min(100,v)); stage.style.setProperty('--p',p+'%'); grip.setAttribute('aria-valuenow',Math.round(p)); }
  function fromX(x){ var r=stage.getBoundingClientRect(); return (x-r.left)/r.width*100; }
  var drag=false;
  stage.addEventListener('pointerdown',function(e){ drag=true; touched=true; try{stage.setPointerCapture(e.pointerId);}catch(_){} set(fromX(e.clientX)); });
  stage.addEventListener('pointermove',function(e){ if(drag) set(fromX(e.clientX)); });
  window.addEventListener('pointerup',function(){ drag=false; });
  grip.addEventListener('keydown',function(e){ var k=e.key; if(k==='ArrowLeft'){touched=true;set(p-3);e.preventDefault();} else if(k==='ArrowRight'){touched=true;set(p+3);e.preventDefault();} else if(k==='Home'){touched=true;set(0);} else if(k==='End'){touched=true;set(100);} });
  set(50);
  /* one-time gentle hint that it's draggable */
  var reduce=matchMedia('(prefers-reduced-motion: reduce)').matches;
  function tween(a,b,d,cb){ var s=null; requestAnimationFrame(function r(t){ if(touched)return; if(s===null)s=t; var k=Math.min((t-s)/d,1),e=1-Math.pow(1-k,3); set(a+(b-a)*e); if(k<1)requestAnimationFrame(r); else if(cb)cb(); }); }
  if(!reduce){
    var io=new IntersectionObserver(function(es){ es.forEach(function(e){ if(e.isIntersecting && !touched){ tween(50,72,700,function(){ tween(72,40,900,function(){ tween(40,52,650); }); }); io.disconnect(); } }); }, {threshold:.5});
    io.observe(stage);
  }
})();

